#TODO: v2.0a - если в слове есть нужная буква, то проверить удовлетворяет ли она условию нужный_сисвол%длинна_слова: не имея даже одной буквы в слове вся шифровка бьётся без возможности дешифровать?

def WordCrypt(text:str) -> str:
	global WORDS
	index = 0
	text = list(text)
	for chr in text:
		chr = chr.lower()
		words = []
		for word in WORDS:
			if chr == ' ':
				words.append(' ')
				break
			elif chr == word[index]:
				words.append(word)
				continue
		print(' ', choice(words))
	return '!EOF'

print('MichiTheCat-RedStar © 2026 - words:', len(WORDS))
print(WordCrypt(input('\n>>> ')))

